module top_module (
    input clk,
    input reset,
    input j,
    input k,
    output q );reg q_reg;
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk) begin
        if (reset)
            q_reg <= 1'b0;
        else if (j && ~k)
            q_reg <= 1'b1;
        else if (~j && k)
            q_reg <= 1'b0;
        else if (j && k)
            q_reg <= ~q_reg;
    end

    assign q = q_reg;

endmodule
